import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ArrowUpward, ArrowDownward } from '@mui/icons-material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface Candidate {
  name: string;
  currentPoll: number;
  pollChange: number;
  trend: number[];
}

interface ElectionData {
  candidates: Candidate[];
  margin: {
    leadingCandidate: string;
    margin: number;
  };
}

export default function Widget() {
  const electionData = response.data as ElectionData;
  const { candidates, margin } = electionData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Election Tracker
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107' }}>
              Leading: {margin.leadingCandidate} by {margin.margin} points
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            {candidates.map((candidate, index) => {
              const isPositive = candidate.pollChange >= 0;
              return (
                <Box key={index}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Box>
                      <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                        {candidate.name}
                      </Typography>
                      <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                        Current Poll: {candidate.currentPoll}%
                      </Typography>
                    </Box>
                    <Chip
                      icon={isPositive ? <ArrowUpward sx={{ fontSize: 16, color: '#10B981' }} /> : <ArrowDownward sx={{ fontSize: 16, color: '#EF4444' }} />}
                      label={`${isPositive ? '+' : ''}${candidate.pollChange.toFixed(1)}%`}
                      sx={{ bgcolor: isPositive ? '#10B981' : '#EF4444', color: '#FFFFFF', height: 24 }}
                    />
                  </Stack>
                  <LineChart
                    height={50}
                    series={[
                      {
                        data: candidate.trend,
                        color: '#FFC107',
                        curve: 'natural',
                        showMark: false,
                      },
                    ]}
                    xAxis={[{ data: candidate.trend.map((_, i) => i), hide: true }]}
                    margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
                    sx={{
                      '& .MuiLineElement-root': {
                        strokeWidth: 1.5,
                      },
                    }}
                  />
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
